const express = require('express');
const bodyParser = require('body-parser');

const app = express();

app.use(bodyParser.json());

const levels = [
  { level: 1, reward: { coins: 100, gems: 5 } },
  { level: 2, reward: { coins: 200, gems: 10 } },
  // ...
];

app.post('/complete-level', (req, res) => {
  const { level, score, time } = req.body;

  const levelData = levels.find(l => l.level === level);

  if (!levelData) {
    return res.status(404).json({ message: 'Level not found' });
  }

  if (score < levelData.minScore || time > levelData.maxTime) {
    return res.status(400).json({ message: 'Invalid score or time' });
  }

  res.json({ reward: levelData.reward });
});

app.post('/claim-reward', (req, res) => {
  const { reward } = req.body;

  // Logic to claim the reward, e.g., update user's account
  // ...

  res.json({ message: 'Reward claimed successfully' });
});

app.listen(3000, () => {
  console.log('Server started on port 3000');
});